def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        for j in range(1, 21):
            weight = 1 / (j ** 2)
            term = (ratio ** j) * weight
            if j % 3 == 0:
                term *= 1.5
            elif j % 2 == 0:
                term *= 1.1
            else:
                term *= 0.7
            if j % 5 == 0:
                term += 0.02 * (capacity - item)
            score += term
        leftover = capacity - item
        if leftover < 0.05 * capacity:
            score *= 2.0
        elif leftover < 0.15 * capacity:
            score *= 1.5
        elif leftover < 0.3 * capacity:
            score *= 1.2
        else:
            score *= 0.85
        if score < 0.05:
            score += 0.1 * np.log1p(leftover)
        if i % 4 == 0:
            score *= 1.15
        elif i % 4 == 1:
            score *= 0.95
        else:
            score *= 1.05
        if i % 7 == 0:
            for k in range(1, 4):
                score += 0.01 * np.sin(i * k + item)
        if leftover < 0.2 * capacity and ratio > 0.7:
            score *= 1.3
            for m in range(1, 6):
                if m % 2 == 0:
                    score += 0.005 * (m ** 2) * np.cos(i + m + item)
                else:
                    score -= 0.003 * m * np.sin(i - m + item)
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        max_priority = 1.0
    else:
        max_priority = np.max(finite_priorities)
    for i in range(len(priorities)):
        if priorities[i] == np.inf:
            priorities[i] = max_priority * 4
    for i in range(len(priorities)):
        if priorities[i] < 0.15:
            priorities[i] += 0.1 * np.sin(i * 0.5 + item * 1.5)
    return priorities
